glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
out vec2 v_gPos;
#if USE_TEXTURE
in vec2 a_uv0;
out vec2 v_uv0;
#endif
void main () {
  vec4 pos = vec4(a_position, 1);
  #if CC_USE_MODEL
  vec4 gPos = cc_matWorld * pos;
  v_gPos = gPos.xy;
  pos = cc_matViewProj * cc_matWorld * pos;
  #else
  v_gPos = pos.xy;
  pos = cc_matViewProj * pos;
  #endif
  #if USE_TEXTURE
  v_uv0 = a_uv0;
  #endif
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 v_color;
in vec2 v_gPos;
#if USE_TEXTURE
in vec2 v_uv0;
uniform sampler2D texture;
#endif
#if USE_TINT
#endif
uniform blocks {
  vec4 albedo;
};
uniform spotLight {
  vec2 spotLightPos;
  vec2 spotLightDir;
  vec4 spotLightParam;
  vec4 spotLightColor;
  float spotLightCutOff;
};
uniform pointLight {
  vec4 pointLightPos[10];
  vec4 pointLightColor[10];
  vec4 pointLightParam[10];
};
void main () {
  vec4 diffuse = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
    diffuse *= texture(texture, v_uv0);
    #if CC_USE_ALPHA_ATLAS_TEXTURE
    diffuse.a *= texture2D(texture, v_uv0 + vec2(0, 0.5)).r;
    #endif
  #endif
  diffuse *= v_color;
  vec3 albedoColor = diffuse.xyz * albedo.xyz * 1.2;
  vec3 lightColor = vec3(0.0);
  vec2 pos;
  float factor;
  float d;
  float kc;
  float kl;
  float kq;
  float identity;
  float k;
  vec4 color;
  for(int i = 0;i<10;i++){
    pos = pointLightPos[i].xy;
    factor = pointLightPos[i].z;
    color = pointLightColor[i];
    d = distance(pos, v_gPos);
    kc = pointLightParam[i].x;
    kl = pointLightParam[i].y;
    kq = pointLightParam[i].z;
    identity = pointLightParam[i].w;
    k = 1.0/(1.0 + kl*d + kq*d*d) * identity;
    lightColor += color.xyz * diffuse.xyz * k;
  }
  pos = spotLightPos;
  color = spotLightColor;
  d = distance(pos, v_gPos);
  kc = spotLightParam.x;
  kl = spotLightParam.y;
  kq = spotLightParam.z;
  identity = spotLightParam.w;
  float k1 = 1.0/(1.0 + kl * d + kq * d * d) * identity;
  factor = cos(spotLightCutOff);
  vec2 dir = v_gPos - pos;
  dir = normalize(dir);
  float theta = dot(dir, spotLightDir);
  float k2 = smoothstep(factor - 0.1, factor, theta);
  vec2 centerPos = spotLightDir * 10.0 + spotLightPos;
  vec2 pixDir = v_gPos - centerPos;
  float dotValue = dot(spotLightDir, pixDir);
  k2 = step(0.0, dotValue) * k2;
  lightColor += color.xyz * diffuse.xyz * k1 * k2;
  vec4 outColor = vec4(albedoColor.xyz+lightColor.xyz, 1.0);
  ALPHA_TEST(outColor);
  gl_FragColor = outColor;
}

